import React, { useState } from "react";
import axios from "axios";
import SearchBar from "../components/SearchBar";
import MovieList from "../components/MovieList";
import MovieDetail from "../components/MovieDetail";

const Home = () => {
  const [movies, setMovies] = useState([]);
  const [selected, setSelected] = useState(null);

  const searchMovies = async (query) => {
    const API_KEY = "YOUR_API_KEY"; // Replace with your TMDB API key

    const response = await axios.get(
      "https://api.themoviedb.org/3/search/movie",
      {
        params: {
          api_key: API_KEY,
          query,
        },
      }
    );

    setMovies(response.data.results);
  };

  return (
    <div className="app-container">
      {!selected ? (
        <>
          {/* ---------- Project Title ---------- */}
          <h1 className="app-title">🎬 Movie Explorer</h1>
          <p className="app-subtitle">
            Discover movies, explore details, and find your next favorite film.
          </p>

          {/* ---------- Search Bar ---------- */}
          <SearchBar onSearch={searchMovies} />

          {/* ---------- Movie List ---------- */}
          <MovieList movies={movies} onSelect={setSelected} />
        </>
      ) : (
        <MovieDetail movie={selected} onClose={() => setSelected(null)} />
      )}
    </div>
  );
};

export default Home;
